import { Hono } from 'hono';
import { serveStatic } from 'hono/static';
import { createClient } from '@supabase/supabase-js';
import { v4 as uuidv4 } from 'uuid';

const app = new Hono();

// Configure Supabase client
const supabaseUrl = process.env.SUPABASE_URL || 'https://your-supabase-url.supabase.co';
const supabaseAnonKey = process.env.SUPABASE_ANON_KEY || 'your-supabase-anon-key';
const supabase = createClient(supabaseUrl, supabaseAnonKey);

// Configure object storage client
const storageProvider = process.env.STORAGE_PROVIDER || 'aws-s3';
const storageRegion = process.env.STORAGE_REGION || 'us-east-1';
const storageBucket = process.env.STORAGE_BUCKET || 'your-storage-bucket';
const storageAccessKeyId = process.env.STORAGE_ACCESS_KEY_ID || 'your-access-key-id';
const storageSecretAccessKey = process.env.STORAGE_SECRET_ACCESS_KEY || 'your-secret-access-key';

// Define file size and mime type limits
const maxFileSize = 10 * 1024 * 1024; // 10MB
const allowedMimeTypes = ['image/jpeg', 'image/png'];

app.post('/upload', async (c) => {
  const form = await c.req.parseForm({ limit: maxFileSize });
  const file = form.file;

  if (!file) {
    return c.json({ error: 'No file provided' }, 400);
  }

  // Validate file size
  if (file.size > maxFileSize) {
    return c.json({ error: 'File size exceeds limit' }, 413);
  }

  // Validate mime type
  if (!allowedMimeTypes.includes(file.mimetype)) {
    return c.json({ error: 'Invalid file type' }, 400);
  }

  // Generate a unique file id
  const fileId = uuidv4();

  try {
    // Upload file to object storage
    const response = await fetch(file.url, {
      method: 'GET',
      headers: { 'Content-Type': file.mimetype },
    });

    if (!response.ok) {
      return c.json({ error: 'Failed to upload file' }, 500);
    }

    const blob = await response.blob();
    const objectStorageUrl = `https://${storageBucket}.s3.${storageRegion}.amazonaws.com/${fileId}`;

    // Write row to files table
    const { data, error } = await supabase.from('files').insert([
      {
        id: fileId,
        name: file.originalname,
        mime_type: file.mimetype,
        size: file.size,
        url: objectStorageUrl,
      },
    ]);

    if (error) {
      return c.json({ error: 'Failed to save file metadata' }, 500);
    }

    // Upload file to object storage
    const uploadResponse = await fetch(objectStorageUrl, {
      method: 'PUT',
      headers: { 'Content-Type': file.mimetype },
      body: blob,
    });

    if (!uploadResponse.ok) {
      return c.json({ error: 'Failed to upload file' }, 500);
    }

    return c.json({ fileId });
  } catch (error) {
    console.error(error);
    return c.json({ error: 'Internal server error' }, 500);
  }
});

export default app;

